var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…사라졌어.","JPN":"消えた……","ENG":"...She's disappeared.","TWN":"……消失了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"단칼에 허신과 침식체들을 전부 소멸시키다니.","JPN":"一撃で虚神と侵食体を全部消滅させるなんて。","ENG":"I can't believe she got rid of the Hollow God and the C.O.s with just one swing of her sword.","TWN":"一劍就將幻神和侵蝕體全部滅掉了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"저 정도 힘이라면… 분명 권능의 일부를 희생시킨 거겠지.","JPN":"あれほどの力なら……きっと、権能の一部を犠牲にしたんだろうね。","ENG":"To exact such strength... she must've sacrificed a part of her power.","TWN":"那種程度的力量……肯定是犧牲了一部分權能吧。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리! 거기 있었군요!","JPN":"パリー！　そこにいたんですね！","ENG":"Parry! There you are!","TWN":"悖悖！原來你在這裡啊！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"방금 엄청난 일이 있었어요!","JPN":"今すごいことが起きました！","ENG":"Something incredible just happened!","TWN":"剛才發生了不得了的事情！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"영웅님이 제 앞에 나타나서 부러진 검을 휘둘렀는데, 검이 별처럼 반짝이더니 전부 휩쓸어버렸어요!","JPN":"英雄様が私の前に現れて折れた剣を振ったら、剣が星のように光って敵を全部倒したんです！","ENG":"The hero appeared in front of me and swung the broken sword! It sparkled like twinkling stars then swept away everything!","TWN":"英雄突然出現在我面前，揮著像星星一樣閃閃發光的斷劍，然後，咻——咻咻！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래 그래- 나도 봤으니 진정해라, 이 녀석아.","JPN":"はいはい、私も見たから落ち着いて。","ENG":"Yeah. I know, I saw it too. So calm down.","TWN":"好啦好啦，我也看到了。冷靜點，小鬼。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그분은… 이렇게 다시 부러진 검 모습으로 돌아왔어요.","JPN":"そして、その方は……また折れた剣に戻ってしまいました。","ENG":"And then she... turned back into the broken sword.","TWN":"然後那位英雄……又變回了這把斷劍的模樣。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그렇게 된 거였군.","JPN":"そういうことか。","ENG":"That's what happened.","TWN":"原來如此。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아마 현실과 차원통로가 이어지면서 본체와 공명한 기억이 멋대로 각성한 거겠지.","JPN":"多分、現実と次元通路が繋がったせいで本体と共鳴した記憶が覚醒したんだ。","ENG":"I think that as the dimensional passage with the Normalside connected, the memories resonated with the original body and awakened on their own.","TWN":"大概是因為和現世連接的次元通道打開了，導致開始與本體共鳴的記憶自己覺醒了吧。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"기억이 화신의 형태로 모습을 갖춘 건 통로에서 흘러나온 클리파 에너지의 영향일 테고 말이야.","JPN":"記憶が化身として現れたのは、通路から流れてきたクリファエネルギーの影響だろうね。","ENG":"And the memory took the form of an incarnation probably due to the influence of the Qlipha energy flowing from the passage.","TWN":"然後受到通道中流出的逆卡巴拉能量的影響，記憶以化身的形式出現了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어…? 클리파? 화신? 하나도 이해 못했어요.","JPN":"え……クリファ？　化身？　まったく意味がわかりません。","ENG":"Huh...? Qlipha? Incarnation? I don't understand any of it.","TWN":"呃……？逆卡巴拉？化身？完全沒聽懂？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하하, 하나도 이해 못하면 어떠냐.","JPN":"あはは、そんなんでどうするんだよ。","ENG":"Haha. It doesn't matter if you didn't understand a thing I just said.","TWN":"哈哈，你不懂也沒關係。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐가 됐건- 덕분에 네가 무사했으니 된 거지.","JPN":"まあ、とにかくおかげであなたが無事だったから、それでいいんだ。","ENG":"Whatever the case, all that matters is that you are safe.","TWN":"不管怎樣，你平安無事就好。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…네!","JPN":"……はい！","ENG":"...Okay!","TWN":"……嗯！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저도 패리 얼굴을 다시 봐서 기뻐요!","JPN":"私もパリーにまた会えて嬉しいです！","ENG":"I'm happy to see you again, Parry!","TWN":"我也很高興能再次見到悖悖的臉！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼, 돌아갈까?","JPN":"じゃあ帰ろうか？","ENG":"Then, shall we go back?","TWN":"那，我們回去吧？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아… 잠시만요.","JPN":"あ……待ってください。","ENG":"Oh... Hold on.","TWN":"啊……等一下。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응? 그건 꽃반지잖아?","JPN":"ん？　花の指輪？","ENG":"Hmm? Isn't that the flower ring?","TWN":"啊？那是花戒指吧？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"거기 두고 가려고?","JPN":"そこに置いて行くの？","ENG":"You're going to leave it behind?","TWN":"你打算把它放在那裡嗎？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"다른 관리국 분들이 남긴 검처럼, 우리가 기억할 이 묘지에 어머니의 이름도 남겨두고 싶어서요.","JPN":"管理局の方々が残した剣みたいに、私たちが記憶するこのお墓にお母さんの名前も残しておきたいんです。","ENG":"Just like the swords of the other Administration people, I want to leave Mother's name at the graveyard that we will remember.","TWN":"就像其他管理局的人留下的劍一樣，我也想在這座我們會銘記的墓地上留下媽媽的名字。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머닌 검 같은 무기는 없었지만, 이 금잔화 한 송이로 떠올릴 수 있으니까요.","JPN":"お母さんは剣のような武器は持ってなかったけど、このキンセンカがあれば思い出せるから。","ENG":"Mother didn't have a sword, but I'll be able to remember her with this single Calendula flower.","TWN":"雖然媽媽沒有劍這樣的武器，但這朵金盞花可以讓我想起她。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그리고…","JPN":"そして……","ENG":"Also...","TWN":"而且……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이제 저는 꽃반지가 필요없어졌거든요.","JPN":"もう私、花の指輪がなくてもいいんです。","ENG":"I don't need a flower ring anymore.","TWN":"現在我不再需要花戒指了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"잘 됐네.","JPN":"よかったね。","ENG":"That's good.","TWN":"很好。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이제 가죠.","JPN":"行きましょう。","ENG":"Let's go now.","TWN":"我們走吧。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리 동료들이 기다리겠어요.","JPN":"パリーの仲間たちが待ってますよ。","ENG":"Your comrades are waiting for us, Parry.","TWN":"悖悖的夥伴在等我們呢。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"잘 있어라, 파블린.","JPN":"さようなら、パブリン。","ENG":"Goodbye, Pavlin.","TWN":"保重，帕芙琳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이번 생은… 동료들 곁에서 편히 쉬길.","JPN":"今生は……仲間たちの側で安らかに眠って。","ENG":"May you rest in peace next to your comrades... in this life.","TWN":"希望這輩子……能在同伴身邊安息。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};